import React from "react";
import { Link as LinkRouter } from "react-router-dom" 

export default function CardsCities({ cardFilter }) {
    return (
        <div>
        {cardFilter.map(city => {
            <div>
                <img src={ProcessingInstruction.env.MONGO_URI + `${city.image}`} alt="hola" />
                <div>
                    <h2>{city.cityname}</h2>
                    <h3>{city.country}</h3>
                </div>
            </div>
        })}
        </div>
    );
}
